1	`timescale 1ns / 1ps
2	
3	/**
4	 * tb_fullchain_realdata.v
5	 *
6	 * Full-chain co-simulation testbench: feeds real ADI CN0566 radar data
7	 * (post-range-FFT, 32 chirps x 1024 bins) through:
8	 *
9	 *   range_bin_decimator (peak detection, 1024→64)
10	 *     → doppler_processor_optimized (Hamming + dual 16-pt FFT)
11	 *
12	 * and compares the Doppler output bit-for-bit against the Python golden
13	 * reference that models the same chain (golden_reference.py).
14	 *
15	 * Stimulus:
16	 *   tb/cosim/real_data/hex/fullchain_range_input.hex
17	 *     32768 x 32-bit packed {Q[31:16], I[15:0]} — 32 chirps x 1024 bins
18	 *
19	 * Expected:
20	 *   tb/cosim/real_data/hex/fullchain_doppler_ref_i.hex
21	 *   tb/cosim/real_data/hex/fullchain_doppler_ref_q.hex
22	 *     2048 x 16-bit signed — 64 range bins x 32 Doppler bins
23	 *
24	 * Pass criteria: ALL 2048 Doppler output bins match exactly.
25	 *
26	 * Compile:
27	 *   iverilog -Wall -DSIMULATION -g2012 \
28	 *     -o tb/tb_fullchain_realdata.vvp \
29	 *     tb/tb_fullchain_realdata.v \
30	 *     range_bin_decimator.v doppler_processor.v xfft_16.v fft_engine.v
31	 *
32	 * Run from: 9_Firmware/9_2_FPGA/
33	 *   vvp tb/tb_fullchain_realdata.vvp
34	 */
35	
36	module tb_fullchain_realdata;
37	
38	// ============================================================================
39	// PARAMETERS
40	// ============================================================================
41	localparam CLK_PERIOD    = 10.0;          // 100 MHz
42	localparam DOPPLER_FFT   = 32;
43	localparam RANGE_BINS    = 64;
44	localparam CHIRPS        = 32;
45	localparam INPUT_BINS    = 1024;
46	localparam DECIM_FACTOR  = 16;
47	
48	localparam TOTAL_INPUT_SAMPLES  = CHIRPS * INPUT_BINS;     // 32768
49	localparam TOTAL_OUTPUT_SAMPLES = RANGE_BINS * DOPPLER_FFT; // 2048
50	localparam SAMPLES_PER_CHIRP    = INPUT_BINS;              // 1024
51	localparam DECIM_PER_CHIRP      = RANGE_BINS;              // 64
52	
53	// Generous timeout: decimator + Doppler processing + margin
54	localparam MAX_CYCLES = 2_000_000;
55	
56	// Error tolerance: 0 = exact match required
57	localparam integer MAX_ERROR = 0;
58	
59	// ============================================================================
60	// CLOCK AND RESET
61	// ============================================================================
62	reg clk;
63	reg reset_n;
64	
65	initial clk = 0;
66	always #(CLK_PERIOD / 2) clk = ~clk;
67	
68	// ============================================================================
69	// DECIMATOR SIGNALS
70	// ============================================================================
71	reg  signed [15:0] decim_i_in;
72	reg  signed [15:0] decim_q_in;
73	reg                decim_valid_in;
74	
75	wire signed [15:0] decim_i_out;
76	wire signed [15:0] decim_q_out;
77	wire               decim_valid_out;
78	wire [5:0]         decim_bin_index;
79	
80	// ============================================================================
81	// DOPPLER SIGNALS
82	// ============================================================================
83	// Wire decimator output directly into Doppler input (matching RTL)
84	wire [31:0] range_data_32bit;
85	wire        range_data_valid;
86	
87	assign range_data_32bit = {decim_q_out, decim_i_out};
88	assign range_data_valid = decim_valid_out;
89	
90	reg         new_chirp_frame;
91	
92	wire [31:0] doppler_output;
93	wire        doppler_valid;
94	wire [4:0]  doppler_bin;
95	wire [5:0]  range_bin;
96	wire        processing_active;
97	wire        frame_complete;
98	wire [3:0]  dut_status;
99	
100	// ============================================================================
101	// DUT INSTANTIATION: Range Bin Decimator
102	// ============================================================================
103	range_bin_decimator #(
104	    .INPUT_BINS(INPUT_BINS),
105	    .OUTPUT_BINS(RANGE_BINS),
106	    .DECIMATION_FACTOR(DECIM_FACTOR)
107	) range_decim (
108	    .clk(clk),
109	    .reset_n(reset_n),
110	    .range_i_in(decim_i_in),
111	    .range_q_in(decim_q_in),
112	    .range_valid_in(decim_valid_in),
113	    .range_i_out(decim_i_out),
114	    .range_q_out(decim_q_out),
115	    .range_valid_out(decim_valid_out),
116	    .range_bin_index(decim_bin_index),
117	    .decimation_mode(2'b01),       // Peak detection mode
118	    .start_bin(10'd0),
119	    .watchdog_timeout()
120	);
121	
122	// ============================================================================
123	// DUT INSTANTIATION: Doppler Processor
124	// ============================================================================
125	doppler_processor_optimized doppler_proc (
126	    .clk(clk),
127	    .reset_n(reset_n),
128	    .range_data(range_data_32bit),
129	    .data_valid(range_data_valid),
130	    .new_chirp_frame(new_chirp_frame),
131	    .doppler_output(doppler_output),
132	    .doppler_valid(doppler_valid),
133	    .doppler_bin(doppler_bin),
134	    .range_bin(range_bin),
135	    .processing_active(processing_active),
136	    .frame_complete(frame_complete),
137	    .status(dut_status)
138	);
139	
140	// Internal DUT state (for debug)
141	wire [2:0] decim_state = range_decim.state;
142	wire [2:0] doppler_state = doppler_proc.state;
143	
144	// ============================================================================
145	// INPUT DATA MEMORY (loaded from hex file)
146	// ============================================================================
147	// 32768 x 32-bit packed {Q[31:16], I[15:0]}
148	reg [31:0] input_mem [0:TOTAL_INPUT_SAMPLES-1];
149	
150	initial begin
151	    $readmemh("tb/cosim/real_data/hex/fullchain_range_input.hex", input_mem);
152	end
153	
154	// ============================================================================
155	// REFERENCE DATA (loaded from hex files)
156	// ============================================================================
157	reg signed [15:0] ref_i [0:TOTAL_OUTPUT_SAMPLES-1];
158	reg signed [15:0] ref_q [0:TOTAL_OUTPUT_SAMPLES-1];
159	
160	initial begin
161	    $readmemh("tb/cosim/real_data/hex/fullchain_doppler_ref_i.hex", ref_i);
162	    $readmemh("tb/cosim/real_data/hex/fullchain_doppler_ref_q.hex", ref_q);
163	end
164	
165	// ============================================================================
166	// DECIMATOR OUTPUT CAPTURE (for debug)
167	// ============================================================================
168	integer decim_out_count;
169	reg signed [15:0] decim_cap_i [0:CHIRPS*RANGE_BINS-1];
170	reg signed [15:0] decim_cap_q [0:CHIRPS*RANGE_BINS-1];
171	
172	// ============================================================================
173	// DOPPLER OUTPUT CAPTURE
174	// ============================================================================
175	reg signed [15:0] cap_out_i [0:TOTAL_OUTPUT_SAMPLES-1];
176	reg signed [15:0] cap_out_q [0:TOTAL_OUTPUT_SAMPLES-1];
177	reg [5:0]  cap_rbin  [0:TOTAL_OUTPUT_SAMPLES-1];
178	reg [4:0]  cap_dbin  [0:TOTAL_OUTPUT_SAMPLES-1];
179	integer out_count;
180	
181	// ============================================================================
182	// PASS / FAIL TRACKING
183	// ============================================================================
184	integer pass_count, fail_count, test_count;
185	
186	task check;
187	    input cond;
188	    input [511:0] label;
189	    begin
190	        test_count = test_count + 1;
191	        if (cond) begin
192	            pass_count = pass_count + 1;
193	        end else begin
194	            $display("  [FAIL] %0s", label);
195	            fail_count = fail_count + 1;
196	        end
197	    end
198	endtask
199	
200	// ============================================================================
201	// COUNT DECIMATOR OUTPUTS (always block)
202	// ============================================================================
203	always @(posedge clk or negedge reset_n) begin
204	    if (!reset_n) begin
205	        decim_out_count <= 0;
206	    end else if (decim_valid_out) begin
207	        if (decim_out_count < CHIRPS * RANGE_BINS) begin
208	            decim_cap_i[decim_out_count] <= decim_i_out;
209	            decim_cap_q[decim_out_count] <= decim_q_out;
210	        end
211	        decim_out_count <= decim_out_count + 1;
212	    end
213	end
214	
215	// ============================================================================
216	// MAIN TEST SEQUENCE
217	// ============================================================================
218	integer i, chirp, sample_idx, cycle_count;
219	integer n_exact, n_within_tol;
220	integer max_err_i, max_err_q;
221	integer abs_diff_i, abs_diff_q;
222	reg signed [31:0] diff_i, diff_q;
223	integer mismatches_printed;
224	reg [31:0] packed_iq;
225	
226	initial begin
227	    // ---- Init ----
228	    pass_count = 0;
229	    fail_count = 0;
230	    test_count = 0;
231	    out_count  = 0;
232	    decim_i_in = 0;
233	    decim_q_in = 0;
234	    decim_valid_in = 0;
235	    new_chirp_frame = 0;
236	    reset_n = 0;
237	
238	    // ---- Reset ----
239	    #(CLK_PERIOD * 10);
240	    reset_n = 1;
241	    #(CLK_PERIOD * 5);
242	
243	    $display("============================================================");
244	    $display("  Full-Chain Real-Data Co-Simulation");
245	    $display("  range_bin_decimator (peak, 1024->64)");
246	    $display("    -> doppler_processor_optimized (Hamming + dual 16-pt FFT)");
247	    $display("  ADI CN0566 Phaser 10.525 GHz X-band FMCW");
248	    $display("  Input:    %0d chirps x %0d range FFT bins = %0d samples",
249	             CHIRPS, INPUT_BINS, TOTAL_INPUT_SAMPLES);
250	    $display("  Expected: %0d range bins x %0d Doppler bins = %0d outputs",
251	             RANGE_BINS, DOPPLER_FFT, TOTAL_OUTPUT_SAMPLES);
252	    $display("============================================================");
253	
254	    // ---- Debug: check hex files loaded ----
255	    $display("  input_mem[0]     = %08h", input_mem[0]);
256	    $display("  input_mem[1023]  = %08h", input_mem[1023]);
257	    $display("  input_mem[32767] = %08h", input_mem[32767]);
258	    $display("  ref_i[0] = %04h, ref_q[0] = %04h", ref_i[0], ref_q[0]);
259	
260	    // ---- Check 1: Both DUTs start in IDLE ----
261	    check(decim_state == 3'd0,
262	          "Decimator starts in ST_IDLE after reset");
263	    check(doppler_state == 3'b000,
264	          "Doppler starts in S_IDLE after reset");
265	
266	    // ---- Pulse new_chirp_frame to start Doppler accumulation ----
267	    @(posedge clk);
268	    new_chirp_frame <= 1;
269	    @(posedge clk);
270	    @(posedge clk);
271	    new_chirp_frame <= 0;
272	    @(posedge clk);
273	
274	    // ---- Feed input data: 32 chirps x 1024 range bins ----
275	    // Each chirp is 1024 consecutive samples. Between chirps, the
276	    // decimator completes (ST_DONE → ST_IDLE) and restarts on the
277	    // next valid input.
278	    $display("\n--- Feeding %0d chirps x %0d bins = %0d samples ---",
279	             CHIRPS, INPUT_BINS, TOTAL_INPUT_SAMPLES);
280	
281	    for (chirp = 0; chirp < CHIRPS; chirp = chirp + 1) begin
282	        // Feed 1024 range bins for this chirp
283	        for (i = 0; i < INPUT_BINS; i = i + 1) begin
284	            @(posedge clk);
285	            sample_idx = chirp * INPUT_BINS + i;
286	            packed_iq = input_mem[sample_idx];
287	            decim_i_in <= packed_iq[15:0];
288	            decim_q_in <= packed_iq[31:16];
289	            decim_valid_in <= 1;
290	        end
291	
292	        // Deassert valid after each chirp to let decimator finish
293	        // (ST_PROCESS → ST_EMIT → ... → ST_DONE → ST_IDLE)
294	        @(posedge clk);
295	        decim_valid_in <= 0;
296	        decim_i_in <= 0;
297	        decim_q_in <= 0;
298	
299	        // Wait for decimator to return to IDLE
300	        // The decimator needs a few cycles for the last EMIT + DONE
301	        cycle_count = 0;
302	        while (decim_state != 3'd0 && cycle_count < 200) begin
303	            @(posedge clk);
304	            cycle_count = cycle_count + 1;
305	        end
306	
307	        if (chirp < 3 || chirp == CHIRPS - 1) begin
308	            $display("  Chirp %0d: IDLE after %0d extra cycles, decim_out=%0d",
309	                     chirp, cycle_count, decim_out_count);
310	        end
311	    end
312	
313	    $display("  All input fed. Total decimator outputs: %0d (expected %0d)",
314	             decim_out_count, CHIRPS * RANGE_BINS);
315	
316	    // ---- Check 3: Decimator produced correct number of outputs ----
317	    check(decim_out_count == CHIRPS * RANGE_BINS,
318	          "Decimator output count == 2048");
319	
320	    // ---- Wait for Doppler processing to complete ----
321	    $display("\n--- Waiting for Doppler to process and emit %0d outputs ---",
322	             TOTAL_OUTPUT_SAMPLES);
323	
324	    cycle_count = 0;
325	    while (out_count < TOTAL_OUTPUT_SAMPLES && cycle_count < MAX_CYCLES) begin
326	        @(posedge clk);
327	        cycle_count = cycle_count + 1;
328	
329	        if (doppler_valid) begin
330	            cap_out_i[out_count] = doppler_output[15:0];
331	            cap_out_q[out_count] = doppler_output[31:16];
332	            cap_rbin[out_count]  = range_bin;
333	            cap_dbin[out_count]  = doppler_bin;
334	            out_count = out_count + 1;
335	        end
336	    end
337	
338	    $display("  Collected %0d Doppler outputs in %0d cycles", out_count,
339	             cycle_count);
340	
341	    // ---- Check 4: Correct Doppler output count ----
342	    check(out_count == TOTAL_OUTPUT_SAMPLES,
343	          "Doppler output count == 2048");
344	
345	    // ---- Check 5: Did not timeout ----
346	    check(cycle_count < MAX_CYCLES,
347	          "Processing completed within timeout");
348	
349	    // ---- Check 6: Doppler returns to IDLE ----
350	    #(CLK_PERIOD * 20);
351	    check(doppler_state == 3'b000,
352	          "Doppler returned to S_IDLE after processing");
353	
354	    // ---- Check 7: Output ordering ----
355	    if (out_count > 0) begin
356	        check(cap_rbin[0] == 0 && cap_dbin[0] == 0,
357	              "First output: range_bin=0, doppler_bin=0");
358	    end
359	    if (out_count == TOTAL_OUTPUT_SAMPLES) begin
360	        check(cap_rbin[TOTAL_OUTPUT_SAMPLES-1] == RANGE_BINS - 1,
361	              "Last output: range_bin=63");
362	        check(cap_dbin[TOTAL_OUTPUT_SAMPLES-1] == DOPPLER_FFT - 1,
363	              "Last output: doppler_bin=31");
364	    end
365	
366	    // ==================================================================
367	    // BIT-FOR-BIT COMPARISON against golden reference
368	    // ==================================================================
369	    $display("");
370	    $display("--- Comparing Doppler RTL output vs Python golden reference ---");
371	    $display("    (full-chain: range FFT -> decimator -> Doppler)");
372	
373	    max_err_i = 0;
374	    max_err_q = 0;
375	    n_exact   = 0;
376	    n_within_tol = 0;
377	    mismatches_printed = 0;
378	
379	    for (i = 0; i < out_count; i = i + 1) begin
380	        diff_i = cap_out_i[i] - ref_i[i];
381	        diff_q = cap_out_q[i] - ref_q[i];
382	
383	        // Absolute value
384	        abs_diff_i = (diff_i < 0) ? -diff_i : diff_i;
385	        abs_diff_q = (diff_q < 0) ? -diff_q : diff_q;
386	
387	        if (abs_diff_i > max_err_i) max_err_i = abs_diff_i;
388	        if (abs_diff_q > max_err_q) max_err_q = abs_diff_q;
389	
390	        if (diff_i == 0 && diff_q == 0)
391	            n_exact = n_exact + 1;
392	
393	        if (abs_diff_i <= MAX_ERROR && abs_diff_q <= MAX_ERROR)
394	            n_within_tol = n_within_tol + 1;
395	
396	        // Print first 20 mismatches for debug
397	        if ((abs_diff_i > MAX_ERROR || abs_diff_q > MAX_ERROR) &&
398	            mismatches_printed < 20) begin
399	            $display("    [%4d] rbin=%2d dbin=%2d RTL=(%6d,%6d) REF=(%6d,%6d) ERR=(%4d,%4d)",
400	                     i, cap_rbin[i], cap_dbin[i],
401	                     $signed(cap_out_i[i]), $signed(cap_out_q[i]),
402	                     $signed(ref_i[i]), $signed(ref_q[i]),
403	                     diff_i, diff_q);
404	            mismatches_printed = mismatches_printed + 1;
405	        end
406	    end
407	
408	    // Per-sample pass/fail check
409	    for (i = 0; i < out_count; i = i + 1) begin
410	        diff_i = cap_out_i[i] - ref_i[i];
411	        diff_q = cap_out_q[i] - ref_q[i];
412	        abs_diff_i = (diff_i < 0) ? -diff_i : diff_i;
413	        abs_diff_q = (diff_q < 0) ? -diff_q : diff_q;
414	        check(abs_diff_i <= MAX_ERROR && abs_diff_q <= MAX_ERROR,
415	              "Full-chain Doppler output bin match");
416	    end
417	
418	    // ==================================================================
419	    // SUMMARY
420	    // ==================================================================
421	    $display("");
422	    $display("============================================================");
423	    $display("  SUMMARY: Full-Chain Real-Data Co-Simulation");
424	    $display("============================================================");
425	    $display("  Chain: range_bin_decimator(peak) -> doppler_processor");
426	    $display("  Input samples:    %0d (%0d chirps x %0d bins)",
427	             TOTAL_INPUT_SAMPLES, CHIRPS, INPUT_BINS);
428	    $display("  Decimator outputs: %0d (expected %0d)",
429	             decim_out_count, CHIRPS * RANGE_BINS);
430	    $display("  Doppler outputs:   %0d (expected %0d)",
431	             out_count, TOTAL_OUTPUT_SAMPLES);
432	    $display("  Exact match:       %0d / %0d", n_exact, out_count);
433	    $display("  Within tolerance:  %0d / %0d (tol=%0d)",
434	             n_within_tol, out_count, MAX_ERROR);
435	    $display("  Max error (I):     %0d", max_err_i);
436	    $display("  Max error (Q):     %0d", max_err_q);
437	    $display("  Structural checks: %0d", 9);
438	    $display("  Data match checks: %0d", out_count);
439	    $display("  Pass: %0d  Fail: %0d", pass_count, fail_count);
440	    $display("============================================================");
441	
442	    if (fail_count == 0)
443	        $display("RESULT: ALL TESTS PASSED (%0d/%0d)", pass_count, test_count);
444	    else
445	        $display("RESULT: %0d TESTS FAILED", fail_count);
446	
447	    $display("============================================================");
448	
449	    #(CLK_PERIOD * 10);
450	    $finish;
451	end
452	
453	// ============================================================================
454	// WATCHDOG
455	// ============================================================================
456	initial begin
457	    #(CLK_PERIOD * MAX_CYCLES * 2);
458	    $display("[TIMEOUT] Simulation exceeded %0d cycles — aborting", MAX_CYCLES * 2);
459	    $display("SOME TESTS FAILED");
460	    $finish;
461	end
462	
463	endmodule
